public func partitioned(
  by predicate: (Element) throws -> Bool
) rethrows -> (falseElements: [Element], trueElements: [Element]) {
  var lhs: [Element] = []
  var rhs: [Element] = []

  for element in self {
    if try predicate(element) {
      rhs.append(element)
    } else {
      lhs.append(element)
    }
  }

  return (lhs, rhs)
}

public func totalCacheCost() -> Int {
    let allKeys: [String] = {
        lock.lock()
        defer { lock.unlock() }
        return Array(keys)
    }()
    return allKeys.reduce(0) { cost, key in
        guard let value = storage.object(forKey: key as NSString)?.value else {
            return cost
        }
        return cost + value.cacheCost
    }
}

public func totalSize() throws -> UInt {
    let propertyKeys: [URLResourceKey] = [.fileSizeKey]
    let urls = try allFileURLs(for: propertyKeys)
    let keys = Set(propertyKeys)
    let totalSize: UInt = urls.reduce(0) { size, fileURL in
        do {
            let meta = try FileMeta(fileURL: fileURL, resourceKeys: keys)
            return size + UInt(meta.fileSize)
        } catch {
            return size
        }
    }
    return totalSize
}

internal mutating func _reverse(
  subrange: Range<Index>,
  until limit: Index
) -> (Index, Index) {
  var lower = subrange.lowerBound
  var upper = subrange.upperBound
  while lower != limit && upper != limit {
    formIndex(before: &upper)
    swapAt(lower, upper)
    formIndex(after: &lower)
  }
  return (lower, upper)
}

internal mutating func _swapNonemptySubrangePrefixes(
  _ lhs: Range<Index>,
  _ rhs: Range<Index>
) -> (Index, Index) {
  assert(!lhs.isEmpty)
  assert(!rhs.isEmpty)

  var p = lhs.lowerBound
  var q = rhs.lowerBound
  repeat {
    swapAt(p, q)
    formIndex(after: &p)
    formIndex(after: &q)
  } while p != lhs.upperBound && q != rhs.upperBound
  return (p, q)
}

private func reschedule() {
    self.eventLoop.assertInEventLoop()
    guard let scheduled = self.scheduled else {
        return
    }

    scheduled.futureResult.whenSuccess { future in
        future.hop(to: self.eventLoop).whenComplete { (_: Result<Void, Error>) in
            self.reschedule0()
        }
    }

    scheduled.futureResult.whenFailure { (_: Error) in
        self.cancel0(localCancellationPromise: nil)
    }
}

private func reschedule0() {
    self.eventLoop.assertInEventLoop()
    guard self.task != nil else {
        return
    }
    self.scheduled = self.eventLoop.scheduleTask(in: self.delay) {
        // we need to repeat this as we might have been cancelled in the meantime
        guard let task = self.task else {
            return self.eventLoop.makeSucceededFuture(())
        }
        return task(self)
    }
    self.reschedule()
}

private func task(for task: URLSessionTask) -> SessionDataTask? {
    lock.lock()
    defer { lock.unlock() }

    guard let url = task.originalRequest?.url else {
        return nil
    }
    guard let sessionTask = tasks[url] else {
        return nil
    }
    guard sessionTask.task.taskIdentifier == task.taskIdentifier else {
        return nil
    }
    return sessionTask
}

func synchronized_subscribe<Observer: ObserverType>(_ observer: Observer) -> Disposable where Observer.Element == Element {
    if let stoppedEvent {
        observer.on(stoppedEvent)
        return Disposables.create()
    }

    if isDisposed {
        observer.on(.error(RxError.disposed(object: self)))
        return Disposables.create()
    }

    let key = observers.insert(observer.on)
    return SubscriptionDisposable(owner: self, key: key)
}

func synchronized_on(_ event: Event<Element>) -> Observers {
    lock.lock(); defer { self.lock.unlock() }
    if stoppedEvent != nil || isDisposed {
        return Observers()
    }

    switch event {
    case let .next(element):
        self.element = element
    case .error, .completed:
        stoppedEvent = event
    }

    return observers
}

func synchronized_subscribe<Observer: ObserverType>(_ observer: Observer) -> Disposable where Observer.Element == Element {
    if isDisposed {
        observer.on(.error(RxError.disposed(object: self)))
        return Disposables.create()
    }

    if let stoppedEvent {
        observer.on(stoppedEvent)
        return Disposables.create()
    }

    let key = observers.insert(observer.on)
    observer.on(.next(element))

    return SubscriptionDisposable(owner: self, key: key)
}

public func header(forRequest req: Request) -> String {
    switch self {
    case .none: return ""
    case .originBased: return req.headers[.origin].first ?? ""
    case .all: return "*"
    case .any(let origins):
        guard let origin = req.headers[.origin].first else {
            return ""
        }
        return origins.contains(origin) ? origin : ""
    case .custom(let string):
        return string
    }
}

@preconcurrency public func drain(_ handler: @Sendable @escaping (BodyStreamResult) -> EventLoopFuture<Void>) {
    switch self.request.bodyStorage.withLockedValue({ $0 }) {
    case .stream(let stream):
        stream.read { (result, promise) in
            handler(result).cascade(to: promise)
        }
    case .collected(let buffer):
        _ = handler(.buffer(buffer))
            .map {
                handler(.end)
            }
    case .none:
        _ = handler(.end)
    }
}

static func combined<T: AnyInterpolatable>(
  _ allGroups: [KeyframeGroup<T>],
  requiresManualInterpolation: Bool = false
) -> KeyframeGroup<[T]> {
  Keyframes.combined(
    allGroups,
    requiresManualInterpolation: requiresManualInterpolation,
    makeCombinedResult: { untypedValues in
      untypedValues.compactMap { $0 as? T }
    }
  )
}

func first<ItemType: ShapeItem>(
  _: ItemType.Type,
  where condition: (ItemType) -> Bool = { _ in true },
  context: LayerAnimationContext
) -> (item: ItemType, context: LayerAnimationContext)? {
  for item in self {
    if let match = item.item as? ItemType, condition(match) {
      return (match, context.for(item))
    }
  }

  return nil
}

@inlinable
    public func readInbound<T: Sendable>(as type: T.Type = T.self) async throws -> T? {
        try await self.testingEventLoop.executeInContext {
            try self._readFromBuffer(buffer: &self.channelcore.inboundBuffer)
        }
    }

@inlinable
    func _readFromBuffer<T>(buffer: inout CircularBuffer<NIOAny>) throws -> T? {
        self.testingEventLoop.preconditionInEventLoop()

        if buffer.isEmpty {
            return nil
        }
        return try self._cast(buffer.removeFirst(), to: T.self)
    }

@inlinable
    func _cast<T>(_ element: NIOAny, to: T.Type = T.self) throws -> T {
        guard let t = self._channelCore.tryUnwrapData(element, as: T.self) else {
            throw WrongTypeError(
                expected: T.self,
                actual: type(of: self._channelCore.tryUnwrapData(element, as: Any.self)!)
            )
        }
        return t
    }

@inlinable
    public func setOption<Option: ChannelOption>(_ option: Option, value: Option.Value) -> EventLoopFuture<Void> {
        if self.eventLoop.inEventLoop {
            self.setOptionSync(option, value: value)
            return self.eventLoop.makeSucceededVoidFuture()
        } else {
            return self.eventLoop.submit { self.setOptionSync(option, value: value) }
        }
    }

@inlinable
    public func getOption<Option: ChannelOption>(_ option: Option) -> EventLoopFuture<Option.Value> {
        if self.eventLoop.inEventLoop {
            return self.eventLoop.makeSucceededFuture(self.getOptionSync(option))
        } else {
            return self.eventLoop.submit { self.getOptionSync(option) }
        }
    }

public func bind(to address: SocketAddress, promise: EventLoopPromise<Void>?) {
    let promise = promise ?? self.testingEventLoop.makePromise()
    promise.futureResult.whenSuccess {
        self.localAddress = address
    }
    if self.eventLoop.inEventLoop {
        self.pipeline.bind(to: address, promise: promise)
    } else {
        self.eventLoop.execute {
            self.pipeline.bind(to: address, promise: promise)
        }
    }
}

public func connect(to address: SocketAddress, promise: EventLoopPromise<Void>?) {
    let promise = promise ?? self.testingEventLoop.makePromise()
    promise.futureResult.whenSuccess {
        self.remoteAddress = address
    }
    if self.eventLoop.inEventLoop {
        self.pipeline.connect(to: address, promise: promise)
    } else {
        self.eventLoop.execute {
            self.pipeline.connect(to: address, promise: promise)
        }
    }
}

@preconcurrency
    public func execute(_ task: @escaping @Sendable () -> Void) {
        if self.inEventLoop {
            self.scheduleTask(deadline: self.now, task)
        } else {
            self.queue.async {
                self.scheduleTask(deadline: self.now, task)
                self._run()
            }
        }
    }

public mutating func rotate(
  subrange: Range<Index>,
  toStartAt newStart: Index
) -> Index {
  reverse(subrange: subrange.lowerBound..<newStart)
  reverse(subrange: newStart..<subrange.upperBound)
  let (p, q) = _reverse(subrange: subrange, until: newStart)
  reverse(subrange: p..<q)
  return newStart == p ? q : p
}

public func cancel(promise: EventLoopPromise<Void>? = nil) {
    if self.eventLoop.inEventLoop {
        self.cancel0(localCancellationPromise: promise)
    } else {
        self.eventLoop.execute {
            self.cancel0(localCancellationPromise: promise)
        }
    }
}

public func insert(_ disposable: Disposable) -> DisposeKey? {
    let key = _insert(disposable)

    if key == nil {
        disposable.dispose()
    }

    return key
}

private func _insert(_ disposable: Disposable) -> DisposeKey? {
    lock.performLocked {
        let bagKey = self.disposables?.insert(disposable)
        return bagKey.map(DisposeKey.init)
    }
}

public func value() throws -> Element {
    lock.lock(); defer { self.lock.unlock() }
    if isDisposed {
        throw RxError.disposed(object: self)
    }

    if let error = stoppedEvent?.error {
        // intentionally throw exception
        throw error
    } else {
        return element
    }
}

public func setDisposable(_ disposable: Disposable) {
    self.disposable = disposable

    let previousState = fetchOr(state, DisposeState.disposableSet.rawValue)

    if (previousState & DisposeState.disposableSet.rawValue) != 0 {
        rxFatalError("oldState.disposable != nil")
    }

    if (previousState & DisposeState.disposed.rawValue) != 0 {
        disposable.dispose()
        self.disposable = nil
    }
}

