func combinedKeyframes(roundedCorners: RoundedCorners?) throws -> KeyframeGroup<Rectangle.Keyframe> {
  let cornerRadius = roundedCorners?.radius ?? cornerRadius
  return Keyframes.combined(
    size,
    position,
    cornerRadius,
    makeCombinedResult: Rectangle.Keyframe.init
  )
}

func percentBasedPointInBounds(from referencePoint: CGPoint) -> CGPoint {
  guard bounds.width > 0, bounds.height > 0 else {
    LottieLogger.shared.assertionFailure("Size must be non-zero before an animation can be played")
    return .zero
  }

  let pointInBounds = CGPoint(
    x: referencePoint.x + CALayer.veryLargeLayerPadding,
    y: referencePoint.y + CALayer.veryLargeLayerPadding
  )

  return CGPoint(
    x: CGFloat(pointInBounds.x) / bounds.width,
    y: CGFloat(pointInBounds.y) / bounds.height
  )
}

private func callCURLHandlerIfNecessary() {
    mutableState.write { mutableState in
        guard let cURLHandler = mutableState.cURLHandler else { return }

        cURLHandler.queue.async { cURLHandler.handler(self.cURLDescription()) }

        mutableState.cURLHandler = nil
    }
}

@inlinable
  public func index(after index: Index) -> Index {
    precondition(index != endIndex, "Advancing past end index")
    guard index.upperBound < base.endIndex else { return endIndex }

    let lowerBound =
      windowSize == 1
      ? index.upperBound
      : base.index(after: index.lowerBound)
    let upperBound = base.index(after: index.upperBound)
    return Index(lowerBound: lowerBound, upperBound: upperBound)
  }

@inlinable
  public func index(after i: Index) -> Index {
    precondition(i != endIndex, "Can't advance past endIndex")
    let upperBound = i.baseRange.upperBound
    guard upperBound != base.endIndex else { return endIndex }
    let end = endOfChunk(startingAt: upperBound)
    return Index(upperBound..<end)
  }

extension AdjacentPairsCollection: BidirectionalCollection
where Base: BidirectionalCollection {
  @inlinable
  public func index(before i: Index) -> Index {
    precondition(i != startIndex, "Can't offset before startIndex")
    let second =
      i == endIndex
      ? base.index(before: base.endIndex)
      : i.first
    let first = base.index(before: second)
    return Index(first: first, second: second)
  }
}

